+function createRunner(responses: Record<string, CommandResult>) {
+  const calls: string[] = [];
+  const runner = async (argv: string[]) => {
+    const key = argv.join(" ");
+    calls.push(key);
+    const res = responses[key] ?? {};
+    return {
+      stdout: res.stdout ?? "",
+      stderr: res.stderr ?? "",
+      code: res.code ?? 0,
+    };
+  };
+  return { runner, calls };
